}

async function execDashboard() {
  const data = await api("/api/exec/dashboard");
  const max = Math.max(...data.byDept.map(x => x.count), 1);
  shell(`
    <section class="grid cols-3">
      <div class="panel metric"><span>资产总数</span><strong>${data.total}</strong></div>
      <div class="panel metric"><span>账面净值</span><strong>${money(data.netValue)}</strong></div>
      <div class="panel metric"><span>异常告警</span><strong>${data.alerts.length}</strong></div>
    </section>
    <section class="grid cols-2" style="margin-top:14px">
      <div class="panel"><h2>部门分布</h2><div class="bars">${data.byDept.map(x => `<div class="bar"><span>${x.name}</span><span><i style="width:${x.count / max * 100}%"></i></span><b>${x.count}</b></div>`).join("")}</div></div>
      <div class="panel"><h2>资产年龄</h2><div class="bars">${Object.entries(data.ageDistribution).map(([k,v]) => `<div class="bar"><span>${k}</span><span><i style="width:${v / data.total * 100}%"></i></span><b>${v}</b></div>`).join("")}</div></div>
    </section>
    <section class="panel" style="margin-top:14px"><h2>异常告警</h2><div class="list">${data.alerts.map(a => `<div class="item">${a}</div>`).join("") || "暂无异常"}</div></section>`, "资产看板大屏");
}

async function insights() {
  const data = await api("/api/exec/insights");
  shell(`<section class="panel"><h2>AI 洞察</h2><p>${data.insight}</p><p class="muted">AI 建议需要人工确认后才能执行。当前 AI 服务：${data.aiAvailable ? "已接入" : "未配置，展示规则兜底建议"}</p><button class="primary">了解详情</button></section>`, "AI 洞察");
}

async function chat() {
  shell(`<div class="chat-box" id="chatBox">${state.chat.map(m => `<div class="msg ${m.me ? "me" : ""}">${m.text}</div>`).join("")}</div>
    <form class="toolbar" id="chatForm" style="margin-top:12px"><input name="message" placeholder="问：我现在有哪些设备 / 我的笔记本什么时候过保 / 我要报修"><button class="primary">发送</button></form>`, "AI 助手");
  $("#chatForm").onsubmit = async e => {
    e.preventDefault();
    const message = new FormData(e.currentTarget).get("message");
    if (!message) return;
    state.chat.push({ me: true, text: message });
    const data = await api("/api/chat", { method: "POST", body: JSON.stringify({ message }) });
    state.chat.push({ me: false, text: data.answer });
    chat();
  };
}

async function profile() {
  shell(`<section class="panel"><h2>${state.user.name}</h2><p>${state.user.email}</p><p>${state.user.department_name || "-"} · ${roleName(state.user.role)}</p><p class="muted">密码修改入口已预留，演示账号统一使用默认密码。</p></section>`, "个人设置");
}

async function render() {
  if (!state.user) return renderLogin();
  try {
    const handlers = {
      home, "my-assets": () => myAssets(false), apply: applyView, tickets: () => tickets(false), chat, notifications, profile,
      approvals, "dept-board": () => myAssets(true), "it-home": itHome, "it-tickets": () => tickets(true), "it-assets": itAssets,
      "it-models": itModels, "it-inbound": inbound, "it-inventory": inventory, "it-users": users, "it-audit": audit,
      "exec-dashboard": execDashboard, "exec-insights": insights
    };
    const allowed = routes.find(r => r[0] === state.view)?.[2]?.includes(state.user.role);
    if (!allowed) state.view = state.user.role === "it" ? "it-home" : state.user.role === "exec" ? "exec-dashboard" : "home";
    await handlers[state.view]();
  } catch (err) {
    shell(`<section class="panel"><h2>出错了</h2><p>${err.message}</p><button class="primary" onclick="location.reload()">刷新</button></section>`, "错误");
  }
}

render();

