import { after, before, describe, test } from "node:test";
import assert from "node:assert/strict";
import { createServer } from "../server.js";

let server;
let baseUrl;

async function api(path, options = {}) {
  const res = await fetch(`${baseUrl}${path}`, {
    ...options,
    headers: {
      "Content-Type": "application/json",
      ...(options.user ? { "X-User-Id": String(options.user) } : {}),
      ...(options.headers || {})
    },
    body: options.body && typeof options.body !== "string" ? JSON.stringify(options.body) : options.body
  });
  const data = await res.json().catch(() => ({}));
  return { res, data };
}

before(async () => {
  process.env.DB_PATH = "/tmp/it-asset-codex-test.db";
  const app = await createServer({ init: true });
  server = app.listen(0);
  await new Promise(resolve => server.once("listening", resolve));
  baseUrl = `http://127.0.0.1:${server.address().port}`;
});

after(async () => {
  await new Promise(resolve => server.close(resolve));
});

describe("competition acceptance smoke", () => {
  test("login works for seeded employee account and business APIs require auth", async () => {
    await api("/api/test/reset", { method: "POST" });
    const login = await api("/api/login", { method: "POST", body: { email: "employee1@company.com", password: "password" } });
    assert.equal(login.res.status, 200);
    assert.equal(login.data.user.email, "employee1@company.com");

    const noAuth = await api("/api/assets");
    assert.equal(noAuth.res.status, 401);
  });

  test("employee asset payloads do not leak price, net value, supplier, or serial number", async () => {
    await api("/api/test/reset", { method: "POST" });
    const list = await api("/api/assets?mine=1", { user: 1 });
    assert.equal(list.res.status, 200);
    assert.ok(list.data.assets.length > 0);
    const raw = JSON.stringify(list.data);
    assert.doesNotMatch(raw, /purchase_price|net_value|supplier|serial_no|16000|3200/);
  });

  test("employees cannot access another employee's asset detail", async () => {
    await api("/api/test/reset", { method: "POST" });
    const detail = await api("/api/assets/AST-104", { user: 1 });
    assert.equal(detail.res.status, 403);
  });

  test("high-value apply flow requires manager, IT assignment, and employee confirmation", async () => {
    await api("/api/test/reset", { method: "POST" });
    const apply = await api("/api/tickets/apply", { method: "POST", user: 1, body: { model_id: "MODEL-L01", reason: "开发用笔记本" } });
    assert.equal(apply.res.status, 201);
    assert.equal(apply.data.ticket.status, "pending_manager");

    const manager = await api(`/api/tickets/${apply.data.ticket.id}/approve`, { method: "POST", user: 3, body: { decision: "approve", note: "同意" } });
    assert.equal(manager.res.status, 200);
    assert.equal(manager.data.ticket.status, "pending_it");

    const it = await api(`/api/tickets/${apply.data.ticket.id}/assign`, { method: "POST", user: 5, body: { asset_id: "AST-102", note: "发放 AST-102" } });
    assert.equal(it.res.status, 200);
    assert.equal(it.data.asset.status, "assigned");

    const confirm = await api(`/api/tickets/${apply.data.ticket.id}/confirm-receipt`, { method: "POST", user: 1, body: { decision: "accept" } });
    assert.equal(confirm.res.status, 200);
    assert.equal(confirm.data.asset.status, "in_use");
    assert.equal(confirm.data.ticket.status, "completed");
  });

  test("scrapped assets cannot be assigned and duplicate return tickets are rejected", async () => {
    await api("/api/test/reset", { method: "POST" });
    const apply = await api("/api/tickets/apply", { method: "POST", user: 1, body: { model_id: "MODEL-M01", reason: "外接显示器" } });
    const mgr = await api(`/api/tickets/${apply.data.ticket.id}/approve`, { method: "POST", user: 3, body: { decision: "approve" } });
    assert.equal(mgr.res.status, 200);
    const badAssign = await api(`/api/tickets/${apply.data.ticket.id}/assign`, { method: "POST", user: 5, body: { asset_id: "AST-108" } });
    assert.equal(badAssign.res.status, 400);

    const first = await api("/api/tickets/return", { method: "POST", user: 1, body: { asset_id: "AST-105", reason: "离职归还" } });
    assert.equal(first.res.status, 409);
  });

  test("AI endpoints return structured fallback without an API key", async () => {
    await api("/api/test/reset", { method: "POST" });
    const rec = await api("/api/ai/recommend", { method: "POST", user: 1, body: { text: "我要做 3D 建模, 对显卡要求高" } });
    assert.equal(rec.res.status, 200);
    assert.ok(rec.data.top_pick);
    assert.ok(rec.data.recommendations[0].score >= 0);

    const triage = await api("/api/ai/triage", { method: "POST", user: 1, body: { text: "屏幕黑屏, 无法开机" } });
    assert.equal(triage.res.status, 200);
    assert.deepEqual(
      { category: triage.data.triage.category, severity: triage.data.triage.severity, need_repair: triage.data.triage.need_repair },
      { category: "hardware", severity: "high", need_repair: true }
    );
  });

  test("repairing assets cannot be transferred", async () => {
    await api("/api/test/reset", { method: "POST" });
    const transfer = await api("/api/tickets/transfer", { method: "POST", user: 5, body: { asset_id: "AST-106", to_user_id: 2, reason: "调拨给产品部" } });
    assert.equal(transfer.res.status, 400);
  });
});

