+function fallbackRecommend(text, user) {
+  const words = String(text || "").toLowerCase();
+  const models = all(`SELECT m.*, (SELECT COUNT(*) FROM assets a WHERE a.model_id=m.id AND a.status='available') AS available_count FROM asset_models m WHERE active=1`);
+  const scored = models.map(model => {
+    let score = 0.25;
+    const corpus = `${model.name} ${model.category} ${model.brand} ${model.specs} ${model.keywords}`.toLowerCase();
+    for (const token of words.split(/[\s,，。;；]+/)) if (token && corpus.includes(token)) score += 0.1;
+    if (/3d|建模|显卡|独显|渲染/.test(words) && model.id === "MODEL-L03") score += 0.55;
+    if (/docker|开发|ide|后端|编程/.test(words) && model.id === "MODEL-L02") score += 0.55;
+    if (/视频|剪辑|设计|移动/.test(words) && model.id === "MODEL-L01") score += 0.45;
+    if (/显示|屏幕|外接|4k/.test(words) && model.category === "monitor") score += 0.5;
+    if (/键盘|外设/.test(words) && model.category === "keyboard") score += 0.5;
+    return {
+      ...modelDto(model, user),
+      score: Math.min(1, Number(score.toFixed(2))),
+      reason: `${model.name} 与需求关键词匹配，${model.available_count > 0 ? `当前可用 ${model.available_count} 台` : "当前暂无库存，可联系 IT 补货"}。`
+    };
+  }).sort((a, b) => b.score - a.score || b.available_count - a.available_count);
+  return scored.slice(0, 3);
+}
