+function fallbackTriage(text) {
+  const value = String(text || "");
+  const hardware = /屏幕|黑屏|不亮|无法开机|开不了机|进水|摔|花屏|电池|充电|硬盘|键盘坏/.test(value);
+  const softwareLow = /慢|卡|软件|更新|崩溃|弹窗|空间/.test(value) && !hardware;
+  if (hardware) {
+    return { category: "hardware", severity: "high", need_repair: true, reason: "描述涉及关键硬件或无法开机，严重影响工作。", self_help: "" };
+  }
+  if (softwareLow) {
+    return { category: "software", severity: "low", need_repair: false, reason: "更像软件或性能问题，可先自助排查。", self_help: "请先重启设备、关闭高占用程序、释放磁盘空间并安装系统更新；仍未解决可坚持报修。" };
+  }
+  return { category: "user_error", severity: "low", need_repair: false, reason: "暂未发现硬件损坏迹象。", self_help: "请补充故障截图、出现时间和影响范围，或联系 IT 协助确认。" };
+}
