import http from "node:http";
import { mkdir, readFile, rm } from "node:fs/promises";
import { existsSync } from "node:fs";
import { execFileSync } from "node:child_process";
import { extname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = fileURLToPath(new URL(".", import.meta.url));
const root = resolve(__dirname);
const publicDir = join(root, "public");
const dbPath = process.env.DB_PATH || join(root, "data", "app.db");
const port = Number(process.env.PORT || 3001);

const TERMINAL_ASSET_STATES = new Set(["scrapped", "lost"]);
const ACTIVE_TICKET_STATUSES = new Set(["pending_manager", "pending_it", "approved", "assigned", "returning", "repairing", "transferring"]);
const STATUS_LABELS = {
  in_stock: "待验收",
  available: "可申领",
  assigned: "待领用",
  in_use: "使用中",
  returning: "归还中",
  repairing: "维修中",
  transferring: "调拨中",
  scrapped: "已报废",
  lost: "已丢失"
};

function q(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  if (typeof value === "number") return Number.isFinite(value) ? String(value) : "NULL";
  return `'${String(value).replaceAll("'", "''")}'`;
}

function sqlite(input, json = false) {
  const args = json ? ["-json", dbPath, input] : [dbPath, input];
  const out = execFileSync("sqlite3", args, { encoding: "utf8" }).trim();
  if (!json) return out;
  return out ? JSON.parse(out) : [];
}

function run(statements) {
  sqlite(Array.isArray(statements) ? `${statements.join(";\n")};` : statements);
}

function all(sql) {
  return sqlite(sql, true);
}

function get(sql) {
  return all(sql)[0] || null;
}

function now() {
  return new Date().toISOString();
}

function json(res, status, data) {
  res.writeHead(status, { "Content-Type": "application/json; charset=utf-8" });
  res.end(JSON.stringify(data));
}

function error(status, message) {
  const err = new Error(message);
  err.status = status;
  return err;
}

async function body(req) {
  const chunks = [];
  for await (const chunk of req) chunks.push(chunk);
  const raw = Buffer.concat(chunks).toString("utf8");
  return raw ? JSON.parse(raw) : {};
}

function tx(statements) {
  run(`BEGIN IMMEDIATE;
${statements.join(";\n")};
COMMIT;`);
}

function audit(actorId, action, entityType, entityId, detail = "") {
  run(`INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail,created_at)
VALUES(${q(actorId)},${q(action)},${q(entityType)},${q(entityId)},${q(detail)},${q(now())})`);
}

function notify(userId, title, bodyText, link = "") {
  if (!userId) return;
  run(`INSERT INTO notifications(id,user_id,title,body,link,created_at)
VALUES(${q(`MSG-${Date.now()}-${Math.floor(Math.random() * 9999)}`)},${q(userId)},${q(title)},${q(bodyText)},${q(link)},${q(now())})`);
}

function addAssetEvent(assetId, actorId, event, fromStatus, toStatus, note = "", ticketId = null) {
  run(`INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at)
