function userFromReq(req) {
  const userId = req.headers["x-user-id"];
  if (!userId) return null;
  return get(`SELECT u.*, d.name AS department_name, d.manager_id AS department_manager_id
FROM users u LEFT JOIN departments d ON d.id=u.department_id
WHERE u.id=${q(userId)} AND u.active=1`);
}

function publicUser(user) {
  if (!user) return null;
  const { password, ...safe } = user;
  return safe;
}

function requireAuth(user) {
  if (!user) throw error(401, "请先登录");
}

function requireRole(user, roles) {
  requireAuth(user);
  if (!roles.includes(user.role)) throw error(403, "你没有权限执行此操作");
}

function canViewAsset(user, asset) {
  if (user.role === "it") return true;
  if (user.role === "exec") return false;
  if (String(asset.holder_id) === String(user.id)) return true;
  if (user.role === "manager" && asset.department_id === user.department_id) return true;
  return false;
}

function netValue(asset) {
  const ageYears = Math.max(0, (Date.now() - new Date(asset.purchase_date).getTime()) / (365 * 24 * 3600 * 1000));
  return Math.max(0, Math.round(Number(asset.purchase_price || 0) * (1 - Math.min(ageYears / 5, 1))));
}

function assetDto(asset, user) {
  const base = {
    id: asset.id,
    asset_no: asset.id,
    model_id: asset.model_id,
    model_name: asset.model_name,
    category: asset.category,
    specs: asset.specs,
    status: asset.status,
    status_label: STATUS_LABELS[asset.status] || asset.status,
    holder_id: asset.holder_id,
    holder_name: asset.holder_name,
    department_id: asset.department_id,
    department_name: asset.department_name,
    purchase_date: asset.purchase_date,
    warranty_until: asset.warranty_until,
    location: asset.location
  };
  if (user.role === "it") {
    return { ...base, serial_no: asset.serial_no, supplier: asset.supplier, purchase_price: asset.purchase_price, net_value: netValue(asset) };
  }
  return base;
}

function modelDto(model, user) {
  const base = {
    id: model.id,
    name: model.name,
    category: model.category,
    brand: model.brand,
    specs: model.specs,
    active: model.active,
    min_stock: model.min_stock,
    available_count: model.available_count ?? availableCount(model.id),
    stock_status: (model.available_count ?? availableCount(model.id)) > 0 ? "有库存" : "暂无库存"
  };
  if (user?.role === "it" || user?.role === "exec") return { ...base, purchase_price: model.purchase_price, warranty_months: model.warranty_months, supplier: model.supplier };
  return base;
}

function availableCount(modelId) {
  return get(`SELECT COUNT(*) AS count FROM assets WHERE model_id=${q(modelId)} AND status='available'`)?.count || 0;
}

function activeTicketFor(assetId, type) {
  return get(`SELECT * FROM tickets WHERE asset_id=${q(assetId)} AND type=${q(type)} AND status NOT IN ('completed','cancelled','rejected')`);
}

function makeTicketId(prefix = "TKT") {
  return `${prefix}-${Date.now().toString(36).toUpperCase()}-${Math.floor(Math.random() * 900 + 100)}`;
}

