route("GET", "/api/summary", async (_req, res, user) => {
  requireAuth(user);
  const myAssets = get(`SELECT COUNT(*) AS c FROM assets WHERE holder_id=${q(user.id)} AND status IN ('assigned','in_use','returning','repairing','transferring')`).c;
  const myTickets = get(`SELECT COUNT(*) AS c FROM tickets WHERE requester_id=${q(user.id)} OR to_user_id=${q(user.id)}`).c;
  const unread = get(`SELECT COUNT(*) AS c FROM notifications WHERE user_id=${q(user.id)} AND read_at IS NULL`).c;
  const pending = user.role === "manager"
    ? get(`SELECT COUNT(*) AS c FROM tickets WHERE status='pending_manager' AND department_id=${q(user.department_id)} AND requester_id != ${q(user.id)}`).c
    : user.role === "it"
      ? get(`SELECT COUNT(*) AS c FROM tickets WHERE status IN ('pending_it','returning','repairing','transferring','approved')`).c
      : 0;
  json(res, 200, { myAssets, myTickets, unread, pending });
});

route("GET", "/api/assets", async (req, res, user) => {
  requireAuth(user);
  const params = new URL(req.url, "http://local").searchParams;
  let where = "1=1";
  if (user.role === "employee") where += ` AND a.holder_id=${q(user.id)}`;
  if (user.role === "manager") where += params.get("dept") === "1" ? ` AND a.department_id=${q(user.department_id)}` : ` AND a.holder_id=${q(user.id)}`;
  if (user.role === "exec") throw error(403, "管理层只能查看聚合看板");
  if (params.get("status")) where += ` AND a.status=${q(params.get("status"))}`;
  const rows = all(`SELECT a.*, m.name AS model_name, m.category, m.specs, m.purchase_price, u.name AS holder_name, d.name AS department_name
FROM assets a JOIN asset_models m ON m.id=a.model_id LEFT JOIN users u ON u.id=a.holder_id LEFT JOIN departments d ON d.id=a.department_id
WHERE ${where} ORDER BY a.id`);
  json(res, 200, { assets: rows.map(asset => assetDto(asset, user)) });
});

route("GET", "/api/assets/:id", async (_req, res, user, p) => {
  requireAuth(user);
  const asset = get(`SELECT a.*, m.name AS model_name, m.category, m.specs, m.purchase_price, u.name AS holder_name, d.name AS department_name
FROM assets a JOIN asset_models m ON m.id=a.model_id LEFT JOIN users u ON u.id=a.holder_id LEFT JOIN departments d ON d.id=a.department_id WHERE a.id=${q(p.id)}`);
  if (!asset) return json(res, 404, { error: "资产不存在" });
  if (!canViewAsset(user, asset)) throw error(403, "你无权查看该资产");
  const events = all(`SELECT e.*, u.name AS actor_name FROM asset_events e LEFT JOIN users u ON u.id=e.actor_id WHERE e.asset_id=${q(p.id)} ORDER BY e.id ASC`);
  json(res, 200, { asset: assetDto(asset, user), events });
});

