route("POST", "/api/ai/recommend", async (req, res, user) => {
  requireAuth(user);
  const b = await body(req);
  const recommendations = fallbackRecommend(b.text, user);
  const aiText = await callLLM("asset_recommendation", b.text, { recommendations });
  audit(user.id, "ai.recommend", "ai", "recommend", String(b.text || "").slice(0, 120));
  json(res, 200, { aiAvailable: Boolean(aiText), aiText, top_pick: recommendations[0] || null, recommendations });
});

route("POST", "/api/ai/triage", async (req, res, user) => {
  requireAuth(user);
  const b = await body(req);
  const triage = fallbackTriage(b.text);
  const aiText = await callLLM("repair_triage", b.text, triage);
