  json(res, 200, { aiAvailable: Boolean(aiText), aiText, triage });
});

route("POST", "/api/chat", async (req, res, user) => {
  requireAuth(user);
  const b = await body(req);
  const message = String(b.message || "");
  const assets = all(`SELECT a.id, m.name AS model_name, a.warranty_until, a.status FROM assets a JOIN asset_models m ON m.id=a.model_id WHERE a.holder_id=${q(user.id)}`);
  let answer = await callLLM("assistant_chat", message, { user: publicUser(user), assets });
  if (!answer) {
    if (/价格|多少钱|净值|折旧|采购价/.test(message) && ["employee", "manager"].includes(user.role)) {
      answer = "这类价格和折旧信息对员工与主管不可见。如确需了解预算，请联系 IT 或财务负责人。";
    } else if (/哪些|资产|设备|有什么/.test(message)) {
      answer = assets.length ? `你当前相关资产：${assets.map(a => `${a.id} ${a.model_name}（${STATUS_LABELS[a.status]}）`).join("；")}` : "你目前没有持有任何设备，可以去申领设备页面提交申请。";
    } else if (/过保|保修/.test(message)) {
      answer = assets.map(a => `${a.id} ${a.model_name} 保修到 ${a.warranty_until}`).join("；") || "没有查到你的资产保修信息。";
    } else if (/报修|申领|归还/.test(message)) {
      answer = "我可以引导你处理这件事，但创建工单前需要你在对应表单里二次确认。当前不会直接创建工单。";
    } else {
      answer = "AI 服务暂未配置。我可以帮你查询资产、保修时间，或引导申领、归还、报修。";
    }
  }
  audit(user.id, "ai.chat", "ai", "chat", message.slice(0, 120));
  json(res, 200, { answer, requiresConfirmation: /报修|申领|归还/.test(message) });
});

route("GET", "/api/tickets", async (req, res, user) => {
  requireAuth(user);
  const params = new URL(req.url, "http://local").searchParams;
  let where = "1=1";
  if (user.role === "employee") where += ` AND (t.requester_id=${q(user.id)} OR t.to_user_id=${q(user.id)})`;
  if (user.role === "manager") where += ` AND (t.department_id=${q(user.department_id)} OR t.requester_id=${q(user.id)} OR t.to_user_id=${q(user.id)})`;
  if (user.role === "exec") throw error(403, "管理层不能查看工单明细");
  if (params.get("status")) where += ` AND t.status=${q(params.get("status"))}`;
  if (params.get("type")) where += ` AND t.type=${q(params.get("type"))}`;
  const rows = all(`SELECT t.*, u.name AS requester_name, tu.name AS to_user_name, m.name AS model_name
FROM tickets t JOIN users u ON u.id=t.requester_id LEFT JOIN users tu ON tu.id=t.to_user_id LEFT JOIN asset_models m ON m.id=t.model_id
WHERE ${where} ORDER BY t.created_at DESC`);
  json(res, 200, { tickets: rows });
});

route("GET", "/api/tickets/:id", async (_req, res, user, p) => {
  requireAuth(user);
  const ticket = get(`SELECT t.*, u.name AS requester_name, tu.name AS to_user_name, m.name AS model_name FROM tickets t JOIN users u ON u.id=t.requester_id LEFT JOIN users tu ON tu.id=t.to_user_id LEFT JOIN asset_models m ON m.id=t.model_id WHERE t.id=${q(p.id)}`);
  if (!ticket) return json(res, 404, { error: "工单不存在" });
  if (user.role === "employee" && ticket.requester_id !== user.id && ticket.to_user_id !== user.id) throw error(403, "你无权查看该工单");
  if (user.role === "manager" && ticket.department_id !== user.department_id && ticket.requester_id !== user.id && ticket.to_user_id !== user.id) throw error(403, "你无权查看该工单");
  const events = all(`SELECT e.*, u.name AS actor_name FROM ticket_events e LEFT JOIN users u ON u.id=e.actor_id WHERE e.ticket_id=${q(p.id)} ORDER BY e.id`);
  json(res, 200, { ticket, events });
});

