    `INSERT INTO tickets(id,type,requester_id,department_id,model_id,status,priority,title,description,ai_result,created_at,updated_at)
VALUES(${q(id)},'apply',${q(user.id)},${q(user.department_id)},${q(model.id)},${q(status)},'normal',${q(`申领 ${model.name}`)},${q(b.reason || "")},${q(b.ai_result || "")},${q(now())},${q(now())})`,
