route("POST", "/api/tickets/:id/approve", async (req, res, user, p) => {
  requireAuth(user);
  const b = await body(req);
  const ticket = get(`SELECT t.*, u.name AS requester_name FROM tickets t JOIN users u ON u.id=t.requester_id WHERE t.id=${q(p.id)}`);
  if (!ticket) throw error(404, "工单不存在");
  if (["completed", "cancelled", "rejected"].includes(ticket.status)) throw error(400, "已结束工单不能再操作");
  const decision = b.decision === "reject" ? "reject" : "approve";
  if (ticket.status === "pending_manager") {
    requireRole(user, ["manager", "it"]);
    if (user.role === "manager" && ticket.department_id !== user.department_id) throw error(403, "不能审批其他部门工单");
    if (user.role === "manager" && ticket.requester_id === user.id) throw error(403, "不能审批自己的工单");
    const next = decision === "reject" ? "rejected" : ticket.type === "transfer" ? "transferring" : "pending_it";
    tx([
      `UPDATE tickets SET status=${q(next)}, manager_decision=${q(b.note || decision)}, updated_at=${q(now())} WHERE id=${q(ticket.id)}`,
      `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},${q(decision === "reject" ? "manager_rejected" : "manager_approved")},${q(b.note || "")},${q(now())})`,
      `INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail,created_at) VALUES(${q(user.id)},'ticket.manager.approve','ticket',${q(ticket.id)},${q(decision)},${q(now())})`
    ]);
    notify(ticket.requester_id, decision === "reject" ? "[申领被驳回] 你的申请被驳回" : "[申领已通过] 你的申领申请已通过初审", b.note || "请查看工单进度。", `/tickets/${ticket.id}`);
  } else if (ticket.status === "pending_it") {
    requireRole(user, ["it"]);
    const next = decision === "reject" ? "rejected" : "approved";
    tx([
      `UPDATE tickets SET status=${q(next)}, it_decision=${q(b.note || decision)}, updated_at=${q(now())} WHERE id=${q(ticket.id)}`,
      `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},${q(decision === "reject" ? "it_rejected" : "it_approved")},${q(b.note || "")},${q(now())})`,
      `INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail,created_at) VALUES(${q(user.id)},'ticket.it.approve','ticket',${q(ticket.id)},${q(decision)},${q(now())})`
    ]);
    notify(ticket.requester_id, decision === "reject" ? "[申领被驳回] 你的申请被 IT 驳回" : "[申领已通过] 等待 IT 分配设备", b.note || "请查看工单进度。", `/tickets/${ticket.id}`);
  } else {
    throw error(400, "当前工单状态不可审批");
  }
  json(res, 200, { ticket: get(`SELECT * FROM tickets WHERE id=${q(ticket.id)}`) });
});

route("POST", "/api/tickets/:id/assign", async (req, res, user, p) => {
  requireRole(user, ["it"]);
  const b = await body(req);
  const ticket = get(`SELECT * FROM tickets WHERE id=${q(p.id)}`);
  if (!ticket) throw error(404, "工单不存在");
  if (!["approved", "pending_it"].includes(ticket.status)) throw error(400, "当前工单不能分配资产");
  const asset = get(`SELECT * FROM assets WHERE id=${q(b.asset_id || "")}`);
  if (!asset) throw error(404, "资产不存在");
  if (TERMINAL_ASSET_STATES.has(asset.status)) {
    audit(user.id, "asset.assign.failed", "asset", asset.id, "终止态资产不可分配");
    throw error(400, "该资产已报废或丢失，不可分配");
  }
  if (asset.status !== "available") throw error(400, "只能分配可用库存资产");
  if (asset.model_id !== ticket.model_id) throw error(400, "资产型号与工单不匹配");
  tx([
    `UPDATE assets SET status='assigned', holder_id=${q(ticket.requester_id)}, department_id=${q(ticket.department_id)} WHERE id=${q(asset.id)} AND status='available'`,
    `UPDATE tickets SET status='assigned', asset_id=${q(asset.id)}, updated_at=${q(now())} WHERE id=${q(ticket.id)}`,
    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'assigned','available','assigned',${q(b.note || "IT 分配资产")},${q(ticket.id)},${q(now())})`,
    `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},'asset_assigned',${q(asset.id)},${q(now())})`,
    `INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail,created_at) VALUES(${q(user.id)},'asset.assign','ticket',${q(ticket.id)},${q(asset.id)},${q(now())})`
  ]);
  notify(ticket.requester_id, "[可领取设备] 你的设备已准备好", `IT 已为你分配 ${asset.id}，请领取后在系统确认。`, `/tickets/${ticket.id}`);
  json(res, 200, { ticket: get(`SELECT * FROM tickets WHERE id=${q(ticket.id)}`), asset: get(`SELECT * FROM assets WHERE id=${q(asset.id)}`) });
});

route("POST", "/api/tickets/:id/confirm-receipt", async (req, res, user, p) => {
  requireAuth(user);
  const b = await body(req);
  const ticket = get(`SELECT * FROM tickets WHERE id=${q(p.id)}`);
  if (!ticket || ticket.requester_id !== user.id) throw error(404, "工单不存在");
