  const asset = get(`SELECT * FROM assets WHERE id=${q(ticket.asset_id)}`);
  if (b.decision === "reject") {
    tx([
      `UPDATE assets SET status='available', holder_id=NULL, department_id=NULL WHERE id=${q(asset.id)}`,
      `UPDATE tickets SET status='cancelled', updated_at=${q(now())} WHERE id=${q(ticket.id)}`,
      `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'receipt_rejected','assigned','available','员工拒绝领用',${q(ticket.id)},${q(now())})`,
      `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},'cancelled','员工拒绝领用',${q(now())})`
    ]);
  } else {
    tx([
      `UPDATE assets SET status='in_use' WHERE id=${q(asset.id)}`,
      `UPDATE tickets SET status='completed', updated_at=${q(now())} WHERE id=${q(ticket.id)}`,
      `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},'receipt_confirmed','assigned','in_use','员工确认领用',${q(ticket.id)},${q(now())})`,
      `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},'completed','员工确认领用',${q(now())})`
    ]);
  }
  audit(user.id, "ticket.receipt.confirm", "ticket", ticket.id, b.decision || "accept");
  json(res, 200, { ticket: get(`SELECT * FROM tickets WHERE id=${q(ticket.id)}`), asset: get(`SELECT * FROM assets WHERE id=${q(asset.id)}`) });
});

