route("POST", "/api/tickets/:id/complete", async (req, res, user, p) => {
  requireRole(user, ["it"]);
  const b = await body(req);
  const ticket = get(`SELECT * FROM tickets WHERE id=${q(p.id)}`);
  if (!ticket || ["completed", "cancelled", "rejected"].includes(ticket.status)) throw error(400, "工单不存在或已结束");
  const asset = get(`SELECT * FROM assets WHERE id=${q(ticket.asset_id)}`);
  let nextStatus = "available";
  let holderExpr = "NULL";
  let deptExpr = "NULL";
  if (ticket.type === "repair" && b.result !== "stock") {
    nextStatus = b.result === "scrap" ? "scrapped" : "in_use";
    holderExpr = nextStatus === "in_use" ? q(ticket.requester_id) : "NULL";
    deptExpr = nextStatus === "in_use" ? q(ticket.department_id) : "NULL";
  }
  if (ticket.type === "return" && b.result === "scrap") nextStatus = "scrapped";
  tx([
    `UPDATE assets SET status=${q(nextStatus)}, holder_id=${holderExpr}, department_id=${deptExpr}, scrap_reason=${q(nextStatus === "scrapped" ? b.note || "无法继续使用" : null)} WHERE id=${q(asset.id)}`,
    `UPDATE tickets SET status='completed', updated_at=${q(now())} WHERE id=${q(ticket.id)}`,
    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,ticket_id,created_at) VALUES(${q(asset.id)},${q(user.id)},${q(ticket.type === "repair" ? "repair_completed" : "return_completed")},${q(asset.status)},${q(nextStatus)},${q(b.note || "")},${q(ticket.id)},${q(now())})`,
    `INSERT INTO ticket_events(ticket_id,actor_id,event,note,created_at) VALUES(${q(ticket.id)},${q(user.id)},'completed',${q(b.note || "")},${q(now())})`
  ]);
  audit(user.id, "ticket.complete", "ticket", ticket.id, b.note || "");
  notify(ticket.requester_id, ticket.type === "repair" ? "[维修进度] 你的设备维修状态已更新" : "[归还已完成] IT 已确认接收", b.note || "处理完成", `/tickets/${ticket.id}`);
