    `INSERT INTO assets(id,serial_no,model_id,status,purchase_date,warranty_until,location,supplier) VALUES(${q(b.asset_id)},${q(b.serial_no || "")},${q(model.id)},'available',${q(b.purchase_date)},${q(b.warranty_until)},${q(b.location || "IT 仓库")},${q(b.supplier || model.supplier)})`,
    `INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note,created_at) VALUES(${q(b.asset_id)},${q(user.id)},'inbound',NULL,'available','扫码/手动入库',${q(now())})`,
    `INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail,created_at) VALUES(${q(user.id)},'asset.inbound','asset',${q(b.asset_id)},${q(model.name)},${q(now())})`
  ]);
  json(res, 201, { asset: get(`SELECT * FROM assets WHERE id=${q(b.asset_id)}`) });
});

route("POST", "/api/inventory/scan", async (req, res, user) => {
  requireRole(user, ["it"]);
  const b = await body(req);
  const codes = Array.isArray(b.asset_ids) ? b.asset_ids : String(b.asset_ids || b.asset_nos || "").split(/[,\n\r\t ]+/).filter(Boolean);
  const assets = all("SELECT id,status FROM assets");
  const known = new Set(assets.map(a => a.id));
  const scanned = new Set(codes);
  const missing = assets.filter(a => !scanned.has(a.id) && !TERMINAL_ASSET_STATES.has(a.status)).map(a => a.id);
  const unknown = [...scanned].filter(id => !known.has(id));
  audit(user.id, "inventory.scan", "inventory", "scan", `scanned=${codes.length}`);
  json(res, 200, { scanned: codes.length, matched: [...scanned].filter(id => known.has(id)), missing, unknown });
});

route("GET", "/api/users", async (_req, res, user) => {
  requireRole(user, ["it", "exec"]);
  const rows = all(`SELECT u.id,u.email,u.name,u.role,u.department_id,u.active,d.name AS department_name,(SELECT COUNT(*) FROM assets a WHERE a.holder_id=u.id AND a.status IN ('assigned','in_use','returning','repairing','transferring')) AS asset_count FROM users u LEFT JOIN departments d ON d.id=u.department_id ORDER BY u.id`);
  json(res, 200, { users: rows });
});

route("POST", "/api/users/:id/offboard", async (_req, res, user, p) => {
  requireRole(user, ["it"]);
  run(`UPDATE users SET active=0 WHERE id=${q(p.id)}`);
  const unreturned = all(`SELECT id, status FROM assets WHERE holder_id=${q(p.id)} AND status IN ('assigned','in_use','returning','repairing','transferring')`);
  audit(user.id, "user.offboard", "user", p.id, `未归还 ${unreturned.map(a => a.id).join(",")}`);
