route("GET", "/api/audit", async (_req, res, user) => {
  requireRole(user, ["it"]);
  json(res, 200, { logs: all(`SELECT l.*, u.name AS actor_name FROM audit_logs l LEFT JOIN users u ON u.id=l.actor_id ORDER BY l.id DESC LIMIT 300`) });
});

route("GET", "/api/exec/dashboard", async (_req, res, user) => {
  requireRole(user, ["it", "exec"]);
  const assets = all(`SELECT a.*, m.purchase_price, m.name AS model_name, m.category, d.name AS department_name FROM assets a JOIN asset_models m ON m.id=a.model_id LEFT JOIN departments d ON d.id=a.department_id`);
  const activeAssets = assets.filter(a => !TERMINAL_ASSET_STATES.has(a.status));
  const net = activeAssets.reduce((sum, asset) => sum + netValue(asset), 0);
  const byDept = all(`SELECT COALESCE(d.name,'库存/未分配') AS name, COUNT(*) AS count FROM assets a LEFT JOIN departments d ON d.id=a.department_id WHERE a.status NOT IN ('scrapped','lost') GROUP BY COALESCE(d.name,'库存/未分配')`);
  const lowStock = all(`SELECT m.id,m.name,m.min_stock,(SELECT COUNT(*) FROM assets a WHERE a.model_id=m.id AND a.status='available') AS available_count FROM asset_models m WHERE m.active=1 AND available_count < m.min_stock`);
  const ages = { "<1年": 0, "1-3年": 0, "3-5年": 0, ">5年": 0 };
  for (const a of activeAssets) {
    const y = (Date.now() - new Date(a.purchase_date).getTime()) / (365 * 24 * 3600 * 1000);
    if (y < 1) ages["<1年"]++; else if (y < 3) ages["1-3年"]++; else if (y < 5) ages["3-5年"]++; else ages[">5年"]++;
  }
  json(res, 200, {
    total: assets.length,
    activeTotal: activeAssets.length,
    netValue: Math.round(net),
    byDept,
    ageDistribution: ages,
    lowStock,
    alerts: lowStock.map(item => `${item.name} 当前可用 ${item.available_count}，低于安全线 ${item.min_stock}`)
  });
});

route("GET", "/api/exec/insights", async (_req, res, user) => {
  requireRole(user, ["it", "exec"]);
  const dashboard = {
    lowStock: all(`SELECT m.name,m.min_stock,(SELECT COUNT(*) FROM assets a WHERE a.model_id=m.id AND a.status='available') AS available_count FROM asset_models m WHERE m.active=1 AND available_count < m.min_stock`)
  };
  const aiText = await callLLM("executive_insight", "生成采购和调拨建议", dashboard);
  const insight = aiText || (dashboard.lowStock.length
    ? `建议优先补充：${dashboard.lowStock.map(x => `${x.name} ${Math.max(1, x.min_stock * 2 - x.available_count)} 台`).join("、")}。理由：当前可用库存低于安全线，可能影响入职和临时替换。`
    : "当前安全库存健康。建议继续关注使用超过 3 年和频繁维修的资产。");
  json(res, 200, { aiAvailable: Boolean(aiText), insight, requiresHumanConfirmation: true });
});

async function serveStatic(req, res) {
  const url = new URL(req.url, "http://local");
  let filePath = join(publicDir, url.pathname === "/" ? "index.html" : url.pathname);
  if (!filePath.startsWith(publicDir)) {
    res.writeHead(403);
    res.end("Forbidden");
    return;
  }
  try {
    const data = await readFile(filePath);
    const type = { ".html": "text/html", ".css": "text/css", ".js": "application/javascript", ".svg": "image/svg+xml" }[extname(filePath)] || "application/octet-stream";
    res.writeHead(200, { "Content-Type": `${type}; charset=utf-8` });
    res.end(data);
  } catch {
    const data = await readFile(join(publicDir, "index.html"));
    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
    res.end(data);
  }
}

export async function createServer({ init = true } = {}) {
  if (init) await initDb();
  return http.createServer(async (req, res) => {
    try {
      const url = new URL(req.url, "http://local");
      const match = routes.find(r => r.method === req.method && r.regex.test(url.pathname));
      if (!match) {
        if (url.pathname.startsWith("/api/")) return json(res, 404, { error: "接口不存在" });
        return serveStatic(req, res);
      }
      const values = match.regex.exec(url.pathname);
      const params = Object.fromEntries(match.keys.map((key, i) => [key, decodeURIComponent(values[i + 1])]));
      const user = userFromReq(req);
      await match.handler(req, res, user, params);
    } catch (err) {
      if (String(err.message || "").includes("UNIQUE constraint failed")) return json(res, 409, { error: "数据已存在，请检查编号是否重复" });
      json(res, err.status || 500, { error: err.status ? err.message : "服务暂时不可用，请稍后重试" });
    }
  });
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  await initDb({ reset: process.argv.includes("--reset") });
  if (process.argv.includes("--init-only")) process.exit(0);
  const server = await createServer({ init: false });
  server.listen(port, () => {
    console.log(`AI IT asset system listening on http://localhost:${port}`);
  });
}

