.model-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
}
.model-card {
  padding: 16px;
  display: grid;
  gap: 12px;
}
.model-card h3 { margin-bottom: 6px; }
.model-card p { color: var(--muted); margin-bottom: 0; }
.model-meta {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}
.model-meta span {
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: 4px 9px;
  font-size: 12px;
  color: #3b4a5f;
  background: #f8fafc;
}

.empty {
  padding: 26px;
  text-align: center;
  color: var(--muted);
  border: 1px dashed var(--line);
  border-radius: 8px;
  background: #fbfdff;
}
.empty strong { display: block; color: var(--ink); }
.detail-slot { margin-top: 16px; }
.timeline {
  border-left: 2px solid var(--line);
  margin-left: 8px;
  padding-left: 16px;
  display: grid;
  gap: 14px;
}
.timeline div { position: relative; }
.timeline div::before {
  content: "";
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--primary);
  position: absolute;
  left: -22px;
  top: 6px;
}
.timeline strong { display: block; }
.timeline span { color: var(--muted); font-size: 13px; }
.timeline p { margin-bottom: 0; color: #46556a; }

.dashboard-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 16px;
}
.bars { display: grid; gap: 12px; }
.bars div {
  display: grid;
  grid-template-columns: 120px 1fr 42px;
  gap: 10px;
  align-items: center;
}
.bars i {
  height: 12px;
  border-radius: 999px;
  background: #e2e8f0;
  overflow: hidden;
}
.bars b {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: var(--primary);
}
.alert {
  padding: 12px;
  border-radius: 8px;
  background: #fff7ed;
  border: 1px solid #fed7aa;
  color: #7c2d12;
}
.list { display: grid; gap: 12px; }
.list.compact { gap: 8px; }
.notice {
  padding: 15px;
  display: grid;
  gap: 8px;
}
.notice.unread { border-color: #9fc1f2; }
.notice h3, .notice p { margin-bottom: 0; }

.chat-panel {
  min-height: 540px;
  display: grid;
  grid-template-rows: 1fr auto;
  overflow: hidden;
}
.chat-log {
  padding: 16px;
  display: grid;
  align-content: start;
  gap: 12px;
  background: #fbfdff;
}
.message {
  max-width: min(720px, 82%);
  padding: 11px 13px;
  border-radius: 8px;
  background: #eaf2ff;
}
.message.me {
  justify-self: end;
  background: #dcfce7;
}
.chat-form {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 10px;
  padding: 14px;
  border-top: 1px solid var(--line);
}
.insight p {
  max-width: 72ch;
  font-size: 18px;
}
.summary-list p { margin-bottom: 8px; }
.error-state p { color: var(--muted); }

.skeleton {
  display: grid;
  gap: 12px;
}
.skeleton span {
  height: 18px;
  border-radius: 999px;
  background: linear-gradient(90deg, #edf2f7, #f8fafc, #edf2f7);
  background-size: 220% 100%;
  animation: shimmer 1.3s infinite linear;
}
.skeleton span:nth-child(2) { width: 70%; }
.skeleton span:nth-child(3) { width: 84%; }
@keyframes shimmer { to { background-position: -220% 0; } }

.toast-region {
  position: fixed;
  right: 18px;
  bottom: 18px;
  display: grid;
  gap: 10px;
  z-index: 100;
}
.toast {
  max-width: 360px;
  border-radius: 8px;
  padding: 12px 14px;
  box-shadow: var(--shadow);
  color: #fff;
  background: #111827;
}
.toast.good { background: var(--good); }
.toast.bad { background: var(--bad); }

@media (max-width: 1020px) {
  .app-shell { grid-template-columns: 1fr; }
  .sidebar { position: static; min-height: auto; }
  .nav { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .metrics, .model-grid, .dashboard-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
}
@media (max-width: 720px) {
  .login-shell { grid-template-columns: 1fr; }
  .login-visual { display: none; }
  .main { padding: 16px; }
  .topbar, .section-head { align-items: stretch; flex-direction: column; }
  .metrics, .model-grid, .dashboard-grid, .form-grid { grid-template-columns: 1fr; }
  .nav { grid-template-columns: 1fr; }
  .chat-form { grid-template-columns: 1fr; }
  .message { max-width: 100%; }
  .bars div { grid-template-columns: 90px 1fr 34px; }
}
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: .01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: .01ms !important;
  }
}

