const app = document.querySelector("#app");
const toastRegion = document.querySelector("#toast");

async function api(path, options = {}) {
  const res = await fetch(path, {
    ...options,
    headers: {
      "Content-Type": "application/json",
      ...(state.user ? { "X-User-Id": state.user.id } : {}),
      ...(options.headers || {})
    },
    body: options.body && typeof options.body !== "string" ? JSON.stringify(options.body) : options.body
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || "服务暂时不可用，请稍后重试");
  return data;
}

function toast(message, type = "info") {
  const item = document.createElement("div");
  item.className = `toast ${type}`;
  item.textContent = message;
  toastRegion.appendChild(item);
  setTimeout(() => item.remove(), 4200);
}

function setView(view) {
  state.view = view;
  location.hash = view;
  render();
}

window.addEventListener("hashchange", () => {
  state.view = location.hash.replace("#", "") || "home";
  render();
});

function roleName(role) {
  return { employee: "员工", manager: "部门主管", it: "IT 管理员", exec: "管理层" }[role] || role;
}

function money(value) {
  return Number(value || 0).toLocaleString("zh-CN", { style: "currency", currency: "CNY", maximumFractionDigits: 0 });
}

function badge(value) {
  const map = {
    in_stock: ["待验收", "neutral"],
    available: ["可申领", "good"],
    assigned: ["待领用", "info"],
    in_use: ["使用中", "info"],
    returning: ["归还中", "warn"],
    repairing: ["维修中", "warn"],
    transferring: ["调拨中", "warn"],
    scrapped: ["已报废", "bad"],
    lost: ["已丢失", "bad"],
    pending_manager: ["待主管审批", "warn"],
    pending_it: ["待 IT 审批", "warn"],
    approved: ["待分配", "info"],
    completed: ["已完成", "good"],
    rejected: ["已驳回", "bad"],
    cancelled: ["已取消", "neutral"]
  };
  const [label, tone] = map[value] || [value, "neutral"];
  return `<span class="badge ${tone}">${label}</span>`;
}

function emptyState(title, action = "") {
  return `<div class="empty"><strong>${title}</strong>${action ? `<p>${action}</p>` : ""}</div>`;
}

function skeleton(lines = 4) {
  return `<div class="panel skeleton">${Array.from({ length: lines }, () => `<span></span>`).join("")}</div>`;
}

