function metric(label, value, helper) {
  return `<article class="metric"><span>${label}</span><strong>${value}</strong><small>${helper}</small></article>`;
}

async function assets({ dept = false, all = false } = {}) {
  shell(dept ? "部门资产" : all ? "资产管理" : "我的资产", skeleton(6));
  const data = await api(`/api/assets${dept ? "?dept=1" : all ? "" : "?mine=1"}`);
  const rows = data.assets.map(asset => `
    <tr>
      <td><strong>${asset.id}</strong><small>${asset.model_name}</small></td>
      <td>${badge(asset.status)}</td>
      <td>${asset.holder_name || "-"}</td>
      <td>${asset.department_name || "-"}</td>
      <td>${asset.warranty_until}</td>
      <td class="actions">
        <button data-detail="${asset.id}">时间轴</button>
        ${asset.holder_id === state.user.id && asset.status === "in_use" ? `<button data-return="${asset.id}">归还</button><button data-repair="${asset.id}">报修</button>` : ""}
        ${state.user.role === "it" && asset.status === "in_use" ? `<button data-transfer="${asset.id}">调拨</button>` : ""}
      </td>
    </tr>`).join("");
  shell(dept ? "部门资产" : all ? "资产管理" : "我的资产", `
    <section class="table-card">
      <table>
        <thead><tr><th>资产</th><th>状态</th><th>持有人</th><th>部门</th><th>保修到期</th><th>操作</th></tr></thead>
        <tbody>${rows || `<tr><td colspan="6">${emptyState("你目前没有持有任何设备", "可以前往申领设备页面提交申请。")}</td></tr>`}</tbody>
      </table>
    </section>
    <section id="detail" class="detail-slot"></section>`, state.user.role === "it" ? `<button class="primary" data-view="it-inbound">新增入库</button>` : "");
  bindAssetActions();
}

function bindAssetActions() {
  document.querySelectorAll("[data-detail]").forEach(btn => btn.addEventListener("click", async () => {
    try {
      const data = await api(`/api/assets/${btn.dataset.detail}`);
      document.querySelector("#detail").innerHTML = `<div class="panel"><div class="section-head"><h2>${data.asset.id} 生命周期</h2><p>${data.asset.model_name} · ${data.asset.location || "-"}</p></div><div class="timeline">${data.events.map(e => `<div><strong>${e.event}</strong><span>${e.created_at}</span><p>${e.from_status || "-"} → ${e.to_status || "-"} ${e.note || ""}</p></div>`).join("")}</div></div>`;
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-return]").forEach(btn => btn.addEventListener("click", async () => {
    const reason = prompt("归还原因", "不再需要该设备");
    if (!reason) return;
    try {
      await api("/api/tickets/return", { method: "POST", body: { asset_id: btn.dataset.return, reason } });
      toast("归还工单已提交", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-repair]").forEach(btn => btn.addEventListener("click", async () => {
    const description = prompt("故障描述", "屏幕黑屏，无法开机");
    if (!description) return;
    try {
      const triage = await api("/api/ai/triage", { method: "POST", body: { text: description } });
      const force = triage.triage.need_repair || confirm(`${triage.triage.self_help}\n\n仍要创建维修工单吗？`);
      if (!force) return;
      await api("/api/tickets/repair", { method: "POST", body: { asset_id: btn.dataset.repair, description, triage: triage.triage, force } });
      toast("维修工单已提交", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-transfer]").forEach(btn => btn.addEventListener("click", async () => {
    const to_user_id = prompt("接收人用户 ID", "2");
    if (!to_user_id) return;
    try {
      await api("/api/tickets/transfer", { method: "POST", body: { asset_id: btn.dataset.transfer, to_user_id, reason: "IT 调拨" } });
      toast("调拨工单已创建", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
}

async function applyView() {
  shell("申领设备", skeleton(5));
  const models = await api("/api/models");
  shell("申领设备", `
    <section class="panel">
      <form id="recommendForm" class="form">
        <label>自然语言需求<textarea name="text" required>我要做 3D 建模，对显卡要求高</textarea></label>
        <button class="primary" type="submit">${icons.spark}<span>AI 推荐型号</span></button>
      </form>
    </section>
    <section id="recommendations" class="model-grid">${models.models.map(modelCard).join("")}</section>`);
  document.querySelector("#recommendForm").addEventListener("submit", async event => {
    event.preventDefault();
    const button = event.currentTarget.querySelector("button");
    button.disabled = true;
    button.querySelector("span").textContent = "推荐中...";
    try {
      const text = new FormData(event.currentTarget).get("text");
      const data = await api("/api/ai/recommend", { method: "POST", body: { text } });
      document.querySelector("#recommendations").innerHTML = data.recommendations.map(item => modelCard(item, text, data.aiText)).join("") || emptyState("暂时没有找到匹配设备", "请换一种描述方式。");
      bindApply();
    } catch (err) { toast(err.message, "bad"); }
    finally {
      button.disabled = false;
      button.querySelector("span").textContent = "AI 推荐型号";
    }
  });
  bindApply();
}

function modelCard(model, reasonText = "", aiText = "") {
  const price = state.user.role === "it" || state.user.role === "exec" ? `<small>${money(model.purchase_price)}</small>` : "";
  return `<article class="model-card">
    <div><h3>${model.name}</h3><p>${model.category} · ${model.specs}</p>${price}</div>
    <div class="model-meta"><span>库存 ${model.available_count}</span><span>${model.stock_status}</span>${model.score !== undefined ? `<span>匹配 ${Math.round(model.score * 100)}%</span>` : ""}</div>
    ${model.reason ? `<p>${model.reason}</p>` : ""}
    ${aiText ? `<p class="muted">${aiText}</p>` : ""}
    <button class="primary" data-apply="${model.id}" data-reason="${encodeURIComponent(reasonText || model.reason || "业务需要")}" ${model.available_count < 1 ? "disabled" : ""}>选择并提交</button>
  </article>`;
}

function bindApply() {
  document.querySelectorAll("[data-apply]").forEach(btn => btn.addEventListener("click", async () => {
    const reason = prompt("申领理由", decodeURIComponent(btn.dataset.reason) || "业务需要");
    if (!reason) return;
    try {
      await api("/api/tickets/apply", { method: "POST", body: { model_id: btn.dataset.apply, reason } });
      toast("申领工单已提交", "good");
      setView("tickets");
    } catch (err) { toast(err.message, "bad"); }
  }));
}

async function tickets({ approvals = false, all = false } = {}) {
  shell(approvals ? "审批工作台" : all ? "工单工作台" : "我的工单", skeleton(6));
  const data = await api("/api/tickets");
  const visible = approvals ? data.tickets.filter(t => t.status === "pending_manager") : data.tickets;
  shell(approvals ? "审批工作台" : all ? "工单工作台" : "我的工单", ticketTable(visible));
  bindTicketActions();
}

function ticketTable(tickets) {
  return `<section class="table-card"><table>
    <thead><tr><th>工单</th><th>类型</th><th>申请人</th><th>状态</th><th>优先级</th><th>操作</th></tr></thead>
    <tbody>${tickets.map(t => `<tr>
      <td><strong>${t.id}</strong><small>${t.title}</small></td>
      <td>${typeName(t.type)}</td><td>${t.requester_name || "-"}</td><td>${badge(t.status)}</td><td>${t.priority}</td>
      <td class="actions">
        <button data-ticket="${t.id}">详情</button>
        ${canApprove(t) ? `<button class="primary" data-approve="${t.id}">通过</button><button class="danger" data-reject="${t.id}">驳回</button>` : ""}
        ${state.user.role === "it" && ["approved", "pending_it"].includes(t.status) && t.type === "apply" ? `<button class="primary" data-assign="${t.id}">分配</button>` : ""}
        ${state.user.id === t.requester_id && t.status === "assigned" ? `<button class="primary" data-receive="${t.id}">确认领用</button>` : ""}
        ${state.user.role === "it" && ["returning", "pending_it"].includes(t.status) && ["return","repair"].includes(t.type) ? `<button class="primary" data-complete="${t.id}" data-type="${t.type}">完结</button>` : ""}
        ${state.user.role === "it" && t.type === "transfer" && ["pending_manager","transferring"].includes(t.status) ? `<button class="primary" data-execute-transfer="${t.id}">执行调拨</button>` : ""}
      </td>
    </tr>`).join("") || `<tr><td colspan="6">${emptyState("暂无工单记录")}</td></tr>`}</tbody>
  </table></section><section id="detail" class="detail-slot"></section>`;
}

function typeName(type) {
  return { apply: "申领", return: "归还", repair: "维修", transfer: "调拨" }[type] || type;
}

function canApprove(ticket) {
  return (state.user.role === "manager" && ticket.status === "pending_manager") || (state.user.role === "it" && ticket.status === "pending_it");
}

function bindTicketActions() {
  document.querySelectorAll("[data-ticket]").forEach(btn => btn.addEventListener("click", async () => {
    try {
      const data = await api(`/api/tickets/${btn.dataset.ticket}`);
      document.querySelector("#detail").innerHTML = `<div class="panel"><div class="section-head"><h2>${data.ticket.id}</h2><p>${data.ticket.description || ""}</p></div><div class="timeline">${data.events.map(e => `<div><strong>${e.event}</strong><span>${e.created_at}</span><p>${e.note || ""}</p></div>`).join("")}</div></div>`;
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-approve]").forEach(btn => btn.addEventListener("click", () => approveTicket(btn.dataset.approve, "approve")));
  document.querySelectorAll("[data-reject]").forEach(btn => btn.addEventListener("click", () => approveTicket(btn.dataset.reject, "reject")));
  document.querySelectorAll("[data-assign]").forEach(btn => btn.addEventListener("click", async () => {
    const asset_id = prompt("输入要分配的可用资产编号", "AST-102");
    if (!asset_id) return;
    try {
      await api(`/api/tickets/${btn.dataset.assign}/assign`, { method: "POST", body: { asset_id, note: "IT 分配资产" } });
      toast("资产已分配，等待员工确认领用", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-receive]").forEach(btn => btn.addEventListener("click", async () => {
    try {
      await api(`/api/tickets/${btn.dataset.receive}/confirm-receipt`, { method: "POST", body: { decision: "accept" } });
      toast("已确认领用", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-complete]").forEach(btn => btn.addEventListener("click", async () => {
    const result = btn.dataset.type === "repair" && !confirm("是否修复完成并归还原持有人？取消将标记报废") ? "scrap" : "fixed";
    const note = prompt("处理备注", result === "scrap" ? "无法修复，报废处理" : "处理完成");
    try {
      await api(`/api/tickets/${btn.dataset.complete}/complete`, { method: "POST", body: { result, note } });
      toast("工单已完结", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
  document.querySelectorAll("[data-execute-transfer]").forEach(btn => btn.addEventListener("click", async () => {
    try {
      await api(`/api/tickets/${btn.dataset.executeTransfer}/execute-transfer`, { method: "POST", body: { note: "调拨完成" } });
      toast("调拨已执行", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
}

async function approveTicket(id, decision) {
  const note = decision === "reject" ? prompt("驳回原因", "不符合当前配置标准") : "审批通过";
  if (!note) return;
  try {
    await api(`/api/tickets/${id}/approve`, { method: "POST", body: { decision, note } });
    toast(decision === "reject" ? "已驳回" : "已通过", "good");
    render();
  } catch (err) { toast(err.message, "bad"); }
}

async function models() {
  shell("型号管理", skeleton(5));
  const data = await api("/api/models");
  shell("型号管理", `<section class="panel"><form id="modelForm" class="form compact">
    <div class="form-grid"><label>型号 ID<input name="id" required placeholder="MODEL-X01"></label><label>名称<input name="name" required></label></div>
    <div class="form-grid"><label>分类<input name="category" required></label><label>品牌<input name="brand"></label></div>
    <label>规格<input name="specs" required></label>
    <div class="form-grid"><label>采购价<input name="purchase_price" type="number" required></label><label>保修月数<input name="warranty_months" type="number" value="24"></label></div>
    <label>关键词<input name="keywords"></label><button class="primary">新增型号</button>
  </form></section><section class="model-grid">${data.models.map(modelCard).join("")}</section>`);
  document.querySelector("#modelForm").addEventListener("submit", async event => {
    event.preventDefault();
    try {
      await api("/api/models", { method: "POST", body: Object.fromEntries(new FormData(event.currentTarget)) });
      toast("型号已新增", "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  });
}

async function inbound() {
  const models = await api("/api/models");
  shell("入库操作", `<section class="panel"><form id="inboundForm" class="form">
    <div class="form-grid"><label>资产编号<input name="asset_id" required placeholder="AST-201"></label><label>序列号<input name="serial_no"></label></div>
    <label>型号<select name="model_id">${models.models.map(m => `<option value="${m.id}">${m.name}</option>`).join("")}</select></label>
    <div class="form-grid"><label>采购日期<input name="purchase_date" type="date" value="2026-05-11"></label><label>保修到期<input name="warranty_until" type="date" value="2028-05-11"></label></div>
    <label>位置<input name="location" value="IT 仓库"></label>
    <button class="primary">确认入库</button>
  </form></section>`);
  document.querySelector("#inboundForm").addEventListener("submit", async event => {
    event.preventDefault();
    try {
      await api("/api/inbound", { method: "POST", body: Object.fromEntries(new FormData(event.currentTarget)) });
      toast("入库成功，库存已更新", "good");
      event.currentTarget.reset();
    } catch (err) { toast(err.message, "bad"); }
  });
}

async function inventory() {
  shell("盘点任务", `<section class="panel"><form id="inventoryForm" class="form">
    <label>扫码结果<textarea name="asset_ids" required>AST-101
AST-102
AST-103</textarea></label>
    <button class="primary">开始比对</button>
  </form></section><section id="inventoryResult" class="detail-slot"></section>`);
  document.querySelector("#inventoryForm").addEventListener("submit", async event => {
    event.preventDefault();
    try {
      const data = await api("/api/inventory/scan", { method: "POST", body: Object.fromEntries(new FormData(event.currentTarget)) });
      document.querySelector("#inventoryResult").innerHTML = `<div class="panel"><h2>盘点结果</h2><div class="summary-list"><p>已扫描 ${data.scanned}，匹配 ${data.matched.length}</p><p>未知编号：${data.unknown.join("、") || "无"}</p><p>未盘到：${data.missing.join("、") || "无"}</p></div></div>`;
    } catch (err) { toast(err.message, "bad"); }
  });
}

async function users() {
  shell("用户管理", skeleton(6));
  const data = await api("/api/users");
  shell("用户管理", `<section class="table-card"><table><thead><tr><th>用户</th><th>角色</th><th>部门</th><th>持有资产</th><th>状态</th><th>操作</th></tr></thead>
  <tbody>${data.users.map(u => `<tr><td><strong>${u.name}</strong><small>${u.email}</small></td><td>${roleName(u.role)}</td><td>${u.department_name || "-"}</td><td>${u.asset_count}</td><td>${u.active ? "在职" : "离职"}</td><td>${u.active ? `<button data-offboard="${u.id}">标记离职</button>` : "-"}</td></tr>`).join("")}</tbody></table></section>`);
  document.querySelectorAll("[data-offboard]").forEach(btn => btn.addEventListener("click", async () => {
    try {
      const data = await api(`/api/users/${btn.dataset.offboard}/offboard`, { method: "POST", body: {} });
      toast(`已标记离职，未归还 ${data.unreturned.length} 台`, "good");
      render();
    } catch (err) { toast(err.message, "bad"); }
  }));
}

async function audit() {
  shell("审计日志", skeleton(6));
  const data = await api("/api/audit");
  shell("审计日志", `<section class="table-card"><table><thead><tr><th>ID</th><th>操作者</th><th>动作</th><th>对象</th><th>详情</th><th>时间</th></tr></thead>
  <tbody>${data.logs.map(l => `<tr><td>${l.id}</td><td>${l.actor_name || "系统"}</td><td>${l.action}</td><td>${l.entity_type} ${l.entity_id || ""}</td><td>${l.detail || ""}</td><td>${l.created_at}</td></tr>`).join("")}</tbody></table></section>`);
}

async function notifications() {
  shell("通知中心", skeleton(4));
  const data = await api("/api/notifications");
  shell("通知中心", `<section class="list">${data.notifications.map(n => `<article class="notice ${n.read_at ? "" : "unread"}"><h3>${n.title}</h3><p>${n.body}</p><small>${n.created_at} · ${n.read_at ? "已读" : "未读"}</small>${n.read_at ? "" : `<button data-read="${n.id}">标记已读</button>`}</article>`).join("") || emptyState("没有新通知")}</section>`);
  document.querySelectorAll("[data-read]").forEach(btn => btn.addEventListener("click", async () => {
    await api(`/api/notifications/${btn.dataset.read}/read`, { method: "POST", body: {} });
    render();
  }));
}

async function execDashboard() {
  shell("资产看板", skeleton(6));
  const data = await api("/api/exec/dashboard");
  const maxDept = Math.max(...data.byDept.map(x => x.count), 1);
  shell("资产看板", `<section class="metrics">
    ${metric("资产总数", data.total, "含终止态")}
    ${metric("在管资产", data.activeTotal, "非报废/丢失")}
    ${metric("账面净值", money(data.netValue), "聚合展示")}
    ${metric("异常告警", data.alerts.length, "低库存")}
  </section>
  <section class="dashboard-grid">
    <div class="panel"><h2>部门分布</h2><div class="bars">${data.byDept.map(x => `<div><span>${x.name}</span><i><b style="width:${(x.count / maxDept) * 100}%"></b></i><strong>${x.count}</strong></div>`).join("")}</div></div>
    <div class="panel"><h2>资产年龄</h2><div class="bars">${Object.entries(data.ageDistribution).map(([k, v]) => `<div><span>${k}</span><i><b style="width:${data.activeTotal ? (v / data.activeTotal) * 100 : 0}%"></b></i><strong>${v}</strong></div>`).join("")}</div></div>
  </section>
  <section class="panel"><h2>异常告警</h2><div class="list compact">${data.alerts.map(alert => `<div class="alert">${alert}</div>`).join("") || emptyState("暂无异常告警")}</div></section>`);
}

async function insights() {
  shell("AI 洞察", skeleton(3));
  const data = await api("/api/exec/insights");
  shell("AI 洞察", `<section class="panel insight"><h2>采购与调拨建议</h2><p>${data.insight}</p><small>AI 建议只做辅助，任何采购、调拨和报废动作都需要人工确认。当前 AI：${data.aiAvailable ? "已接入" : "未配置，使用规则兜底"}</small></section>`);
}

async function chat() {
  shell("AI 助手", `<section class="chat-panel"><div id="chatLog" class="chat-log">${state.chat.map(m => `<div class="message ${m.me ? "me" : ""}">${m.text}</div>`).join("") || `<div class="message">你可以问：我现在有哪些资产、我的笔记本什么时候过保、我要报修。</div>`}</div><form id="chatForm" class="chat-form"><label class="sr-only">消息</label><input name="message" placeholder="输入问题" autocomplete="off"><button class="primary">发送</button></form></section>`);
  document.querySelector("#chatForm").addEventListener("submit", async event => {
    event.preventDefault();
    const input = event.currentTarget.message;
    const message = input.value.trim();
    if (!message) return;
    state.chat.push({ me: true, text: message });
    input.value = "";
    try {
      const data = await api("/api/chat", { method: "POST", body: { message } });
      state.chat.push({ me: false, text: data.answer });
    } catch (err) {
      state.chat.push({ me: false, text: err.message });
    }
    chat();
  });
}

async function render() {
  if (!state.user) return renderLogin();
  const allowed = nav.find(item => item[0] === state.view)?.[3]?.includes(state.user.role);
  if (!allowed) state.view = state.user.role === "it" ? "it-home" : state.user.role === "exec" ? "exec-dashboard" : "home";
  const handlers = {
    home,
    "my-assets": () => assets(),
    apply: applyView,
    tickets: () => tickets(),
    chat,
    notifications,
    approvals: () => tickets({ approvals: true }),
    dept: () => assets({ dept: true }),
    "it-home": home,
    "it-assets": () => assets({ all: true }),
    "it-tickets": () => tickets({ all: true }),
    "it-models": models,
    "it-inbound": inbound,
    "it-inventory": inventory,
    "it-users": users,
    "it-audit": audit,
    "exec-dashboard": execDashboard,
    "exec-insights": insights
  };
  try {
    await handlers[state.view]();
  } catch (err) {
    shell("出错了", `<section class="panel error-state"><h2>页面暂时不可用</h2><p>${err.message}</p><button class="primary" onclick="location.reload()">刷新</button></section>`);
  }
}

render();

